        // the correct CRC and compressed/uncompressed sizes
        if (raf != null) {
            long save = raf.getFilePointer();
            boolean actuallyNeedsZip64 = entry.entry.getSize() >= ZIP64_MAGIC
                || entry.entry.getCompressedSize() >= ZIP64_MAGIC;

