            writeOut(ZipLong.getBytes(entry.entry.getCrc()));
            if (!hasZip64Extra(entry.entry) || !actuallyNeedsZip64) {
                writeOut(ZipLong.getBytes(entry.entry.getCompressedSize()));
                writeOut(ZipLong.getBytes(entry.entry.getSize()));
            } else {
